import{_ as a}from"./index.46415361.js";import{e as i,o as s,c as n,a as e,n as d,u as r,l as c,p as l,m as h}from"./vendor.5df91275.js";var u="/assets/jamiemclean_thumb.efe6ca05.jpg";const t=o=>(l("data-v-e3a20e86"),o=o(),h(),o),p={class:"detail-page"},g=c("<section data-v-e3a20e86><h3 data-v-e3a20e86>Summary</h3><h4 data-v-e3a20e86>Role: Director, Media Coordinator, Videographer</h4><p data-v-e3a20e86> We were tasked to create a series of seven music videos for our client Jame McLean showcasing selected songs from his new album Paradise Found. The videos were split into two sets. In the first set, our client wanted more than just the &quot;in-studio&quot; footage so I concepted four varying ideas utilizing the available studio space to help differentiate each song that would also be accompanied by b-roll and decisive lighting. The second set of three songs featured a &quot;live-performance&quot; vibe. During production, I helped with setup, camera placement and breakdown of equipment, filming some b-roll and take photos, acting as camera operator and working with talent and staff to ensure communication. Post-production, I worked closely during the editing process to determine the best shots from the footage. </p></section><section data-v-e3a20e86><h3 data-v-e3a20e86>First Set:</h3><h4 data-v-e3a20e86>Pre-Production:</h4><p data-v-e3a20e86> The first set included four songs. They were to be done in the studio with each video varying in concept. Prior to production, I had already visited the studio so my main task was to come up with four varying concepts that could be possible within the 8 hours of studio time the client had booked. For the first song \u201CThis Is It\u201D, I assembled a document including other video inspiration, summary of approach, and a loose storyboard utilizing Canva so the client could gather an idea of what I had in mind and also gain insight into how I would be approaching the songs. </p><p data-v-e3a20e86> For the other three songs I sent ideas of what would be possible within the studio space and the mood I was going for on each song. We would use our own team\u2019s lighting to add color which would add differentiation to each video. </p></section><section data-v-e3a20e86><h4 data-v-e3a20e86>Production:</h4><p data-v-e3a20e86> On production day, we utilized the studio room and sections of the studio\u2019s building to pair each song up with it\u2019s own imagery. Each song had it\u2019s own section of the studio room, dedicated space in the building for takes and differential colors for lighting. I worked closely with the studio staff and directed them, our videography team and the talent to ensure all four songs would have several takes and be completed within the day. Due to time constraints, we alternated settings to gather footage while the staff made changes in the studio. In between shots, I also would try to video behind the scenes footage as additional material to be used during the editing process. </p></section><section data-v-e3a20e86><h4 data-v-e3a20e86>Post-Production:</h4><p data-v-e3a20e86> I oversaw the editing process with my teammate who handled the direct usage of the software. Editing generally spanned three days per video, including footage organization, rendering 4k to 1080p alongside project file setup as well as the rough cut before some fine tuning. The client would make one round of suggested edits before we update and send them the final version. During this process I would occasionally act as client liaison, working with the client on timelines and giving them updates on the process of the video. </p></section>",4),m=t(()=>e("div",{class:"video-container"},[e("iframe",{class:"video",src:"https://www.youtube.com/embed/vQ45rgPAAPU",title:"",frameborder:"0",width:"100%",height:"100%",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})],-1)),w=t(()=>e("div",{class:"video-container"},[e("iframe",{class:"video",src:"https://www.youtube.com/embed/ffqgBR_K_7w",title:"",frameborder:"0",width:"100%",height:"100%",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})],-1)),f=t(()=>e("section",null,[e("h3",null,"Second Set:"),e("h4",null,"Production:"),e("p",null,' The second set included three songs that would be released on the client\u2019s YouTube page as promotional material. These followed a more generic format of recording the band on stage as a "live" performance with the venue\u2019s staff handling lighting. Our team worked closely with the band to change positioning, outfits and possible stage components for each song. Each song also differed in lighting to try to give them a sense of variation upon being released. ')],-1)),v=t(()=>e("section",null,[e("h4",null,"Post Production:"),e("p",null," These songs were edited in the same way as the first set, where I worked closely with the editor to look through all the footage, picking out the best to be utilized in the song. Editing spanned two days with one round of changes indicated by our client. ")],-1)),b=t(()=>e("div",{class:"video-container"},[e("iframe",{class:"video",src:"https://www.youtube.com/embed/qW0KwT2FNAg",title:"",frameborder:"0",width:"100%",height:"100%",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})],-1)),y=t(()=>e("section",{class:"next-section"},[e("h4",null,[e("a",{href:"/blues-and-beyond"},"\u2190 Prev: Blues and Beyond ")]),e("h4",null,[e("a",{href:"/caleb-hawley"}," Next: Caleb Hawley \u2192")])],-1)),_=i({setup(o){return(I,k)=>(s(),n("div",p,[e("h2",{class:"title",style:d({backgroundImage:`url(${r(u)})`})}," 01 // Jamie McLean Band ",4),g,m,w,f,v,b,y]))}});var B=a(_,[["__scopeId","data-v-e3a20e86"]]);export{B as default};
